import{_ as t,C as l,o as n,c as o,j as e,a as i,b as u,w as r,E as k,a6 as d,a5 as h}from"./chunks/framework.CiX2n_L2.js";const S=JSON.parse('{"title":"Kesalahan yang Sering Dilakukan Peserta","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ppdgs/extra/kesalahan-umum.md","filePath":"ppdgs/extra/kesalahan-umum.md","lastUpdated":null}'),m={name:"ppdgs/extra/kesalahan-umum.md"};function p(g,a,b,c,f,P){const s=l("Mermaid");return n(),o("div",null,[a[1]||(a[1]=e("h1",{id:"kesalahan-yang-sering-dilakukan-peserta",tabindex:"-1"},[i("Kesalahan yang Sering Dilakukan Peserta "),e("a",{class:"header-anchor",href:"#kesalahan-yang-sering-dilakukan-peserta","aria-label":'Permalink to "Kesalahan yang Sering Dilakukan Peserta"'},"​")],-1)),a[2]||(a[2]=e("p",null,"Pelajari dari kesalahan umum peserta lain agar pendaftaran Anda berjalan lancar.",-1)),(n(),u(d,null,{default:r(()=>[k(s,{id:"mermaid-6",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BKesalahan%20Umum%5D%20--%3E%20B%5BData%20Tidak%20Sesuai%5D%0A%20%20%20%20A%20--%3E%20C%5BDokumen%20Bermasalah%5D%0A%20%20%20%20A%20--%3E%20D%5BDeskripsi%20Diri%5D%0A%20%20%20%20A%20--%3E%20E%5BPembayaran%20Salah%5D%0A%20%20%20%20A%20--%3E%20F%5BTeknis%5D%0A%0A%20%20%20%20B%20--%3E%20B1%5BNama%20beda%20dengan%20KTP%5D%0A%20%20%20%20B%20--%3E%20B2%5BTanggal%20lahir%20salah%5D%0A%20%20%20%20B%20--%3E%20B3%5BAlamat%20tidak%20lengkap%5D%0A%0A%20%20%20%20C%20--%3E%20C1%5BFile%20melebihi%201%20MB%5D%0A%20%20%20%20C%20--%3E%20C2%5BFormat%20bukan%20JPG%5D%0A%20%20%20%20C%20--%3E%20C3%5BDokumen%20tidak%20jelas%5D%0A%0A%20%20%20%20D%20--%3E%20D1%5BJawaban%20terlalu%20singkat%5D%0A%20%20%20%20D%20--%3E%20D2%5BTidak%20menjawab%20semua%20sub-pertanyaan%5D%0A%20%20%20%20D%20--%3E%20D3%5BCopy-paste%20jawaban%20sama%5D%0A%0A%20%20%20%20E%20--%3E%20E1%5BNominal%20tidak%20sesuai%5D%0A%20%20%20%20E%20--%3E%20E2%5BBukti%20tidak%20jelas%5D%0A%20%20%20%20E%20--%3E%20E3%5BTransfer%20ke%20rekening%20salah%5D%0A%0A%20%20%20%20F%20--%3E%20F1%5BKoneksi%20putus%5D%0A%20%20%20%20F%20--%3E%20F2%5BBrowser%20lama%5D%0A%20%20%20%20F%20--%3E%20F3%5BCache%20bermasalah%5D%0A"})]),fallback:r(()=>[...a[0]||(a[0]=[i(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=h('<h2 id="kesalahan-data-diri" tabindex="-1">Kesalahan Data Diri <a class="header-anchor" href="#kesalahan-data-diri" aria-label="Permalink to &quot;Kesalahan Data Diri&quot;">​</a></h2><h3 id="_1-nama-tidak-sesuai-ktp" tabindex="-1">1. Nama Tidak Sesuai KTP <a class="header-anchor" href="#_1-nama-tidak-sesuai-ktp" aria-label="Permalink to &quot;1. Nama Tidak Sesuai KTP&quot;">​</a></h3><p><strong>Masalah:</strong> Menggunakan nama panggilan atau gelar saat mengisi nama.</p><p><strong>Solusi:</strong> Gunakan nama lengkap sesuai KTP tanpa gelar akademik.</p><h3 id="_2-tanggal-lahir-salah" tabindex="-1">2. Tanggal Lahir Salah <a class="header-anchor" href="#_2-tanggal-lahir-salah" aria-label="Permalink to &quot;2. Tanggal Lahir Salah&quot;">​</a></h3><p><strong>Masalah:</strong> Format tanggal lahir terbalik (bulan-tanggal-tahun).</p><p><strong>Solusi:</strong> Gunakan format DD/MM/YYYY sesuai petunjuk.</p><h3 id="_3-alamat-tidak-lengkap" tabindex="-1">3. Alamat Tidak Lengkap <a class="header-anchor" href="#_3-alamat-tidak-lengkap" aria-label="Permalink to &quot;3. Alamat Tidak Lengkap&quot;">​</a></h3><p><strong>Masalah:</strong> Alamat ditulis singkat, tanpa RT/RW atau kode pos.</p><p><strong>Solusi:</strong> Tulis alamat lengkap sesuai KTP.</p><h2 id="kesalahan-dokumen" tabindex="-1">Kesalahan Dokumen <a class="header-anchor" href="#kesalahan-dokumen" aria-label="Permalink to &quot;Kesalahan Dokumen&quot;">​</a></h2><h3 id="_4-file-melebihi-1-mb" tabindex="-1">4. File Melebihi 1 MB <a class="header-anchor" href="#_4-file-melebihi-1-mb" aria-label="Permalink to &quot;4. File Melebihi 1 MB&quot;">​</a></h3><p><strong>Masalah:</strong> Ukuran file melebihi batas maksimal 1 MB.</p><p><strong>Solusi:</strong></p><table tabindex="0"><thead><tr><th>Jenis Dokumen</th><th>Solusi</th></tr></thead><tbody><tr><td>Foto</td><td>Kompres dengan aplikasi image compressor</td></tr><tr><td>Scan Ijazah</td><td>Scan 300 DPI, kompres ke JPG</td></tr><tr><td>Sertifikat</td><td>Gunakan screenshot atau scan dengan resolusi rendah</td></tr></tbody></table><h3 id="_5-format-file-bukan-jpg" tabindex="-1">5. Format File Bukan JPG <a class="header-anchor" href="#_5-format-file-bukan-jpg" aria-label="Permalink to &quot;5. Format File Bukan JPG&quot;">​</a></h3><p><strong>Masalah:</strong> Mengupload file dengan format yang tidak didukung (HEIC, BMP, PNG untuk dokumen wajib, DOCX, PDF).</p><p><strong>Solusi:</strong></p><ul><li>Semua dokumen wajib harus dalam format <strong>JPG</strong></li><li>Hanya Bukti Pembayaran yang bisa menggunakan <strong>PNG</strong></li><li>Gunakan converter online gratis jika perlu</li></ul><h3 id="_6-dokumen-tidak-jelas" tabindex="-1">6. Dokumen Tidak Jelas <a class="header-anchor" href="#_6-dokumen-tidak-jelas" aria-label="Permalink to &quot;6. Dokumen Tidak Jelas&quot;">​</a></h3><p><strong>Masalah:</strong> Scan dokumen buram, terpotong, atau terlalu kecil.</p><p><strong>Solusi:</strong></p><ul><li>Scan dengan resolusi 300 DPI</li><li>Pastikan seluruh dokumen terlihat dalam frame</li><li>Gunakan latar putih polos</li><li>Cahaya cukup saat memotret</li></ul><h3 id="_7-resolusi-melebihi-2500-x-1600-px" tabindex="-1">7. Resolusi Melebihi 2500 x 1600 px <a class="header-anchor" href="#_7-resolusi-melebihi-2500-x-1600-px" aria-label="Permalink to &quot;7. Resolusi Melebihi 2500 x 1600 px&quot;">​</a></h3><p><strong>Masalah:</strong> Gambar beresolusi terlalu tinggi sehingga gagal diupload.</p><p><strong>Solusi:</strong> Resize gambar ke resolusi maksimal 2500 x 1600 piksel sebelum upload.</p><h3 id="_8-dokumen-belum-dilegalisir" tabindex="-1">8. Dokumen Belum Dilegalisir <a class="header-anchor" href="#_8-dokumen-belum-dilegalisir" aria-label="Permalink to &quot;8. Dokumen Belum Dilegalisir&quot;">​</a></h3><p><strong>Masalah:</strong> Ijazah yang diupload belum dilegalisir (hanya fotokopi).</p><p><strong>Solusi:</strong> Legalisir ijazah S1 dan ijazah profesi dokter di institusi pendidikan asal.</p><h2 id="kesalahan-deskripsi-diri" tabindex="-1">Kesalahan Deskripsi Diri <a class="header-anchor" href="#kesalahan-deskripsi-diri" aria-label="Permalink to &quot;Kesalahan Deskripsi Diri&quot;">​</a></h2><h3 id="_9-jawaban-terlalu-singkat" tabindex="-1">9. Jawaban Terlalu Singkat <a class="header-anchor" href="#_9-jawaban-terlalu-singkat" aria-label="Permalink to &quot;9. Jawaban Terlalu Singkat&quot;">​</a></h3><p><strong>Masalah:</strong> Setiap pertanyaan deskripsi diri membutuhkan jawaban yang cukup mendetail, namun peserta hanya menulis 1-2 kalimat.</p><p><strong>Solusi:</strong> Tulis jawaban minimal 3-5 paragraf yang menjelaskan pengalaman, motivasi, dan relevansi dengan program studi yang dituju.</p><h3 id="_10-tidak-menjawab-semua-sub-pertanyaan" tabindex="-1">10. Tidak Menjawab Semua Sub-Pertanyaan <a class="header-anchor" href="#_10-tidak-menjawab-semua-sub-pertanyaan" aria-label="Permalink to &quot;10. Tidak Menjawab Semua Sub-Pertanyaan&quot;">​</a></h3><p><strong>Masalah:</strong> Setiap pertanyaan deskripsi diri memiliki beberapa sub-poin yang harus dijawab. Peserta sering melewatkan beberapa sub-poin.</p><p><strong>Solusi:</strong> Baca pertanyaan dengan saksama dan pastikan setiap sub-poin terjawab dalam tulisan Anda.</p><h3 id="_11-copy-paste-jawaban-yang-sama" tabindex="-1">11. Copy-Paste Jawaban yang Sama <a class="header-anchor" href="#_11-copy-paste-jawaban-yang-sama" aria-label="Permalink to &quot;11. Copy-Paste Jawaban yang Sama&quot;">​</a></h3><p><strong>Masalah:</strong> Menggunakan jawaban yang persis sama untuk pertanyaan yang berbeda.</p><p><strong>Solusi:</strong> Setiap pertanyaan memiliki konteks berbeda. Sesuaikan jawaban untuk masing-masing pertanyaan secara spesifik.</p><h3 id="_12-tidak-memeriksa-ejaan" tabindex="-1">12. Tidak Memeriksa Ejaan <a class="header-anchor" href="#_12-tidak-memeriksa-ejaan" aria-label="Permalink to &quot;12. Tidak Memeriksa Ejaan&quot;">​</a></h3><p><strong>Masalah:</strong> Terdapat banyak typo dan kesalahan penulisan dalam jawaban deskripsi diri.</p><p><strong>Solusi:</strong> Gunakan fitur spell check atau baca ulang jawaban sebelum menyimpan.</p><h2 id="kesalahan-pembayaran" tabindex="-1">Kesalahan Pembayaran <a class="header-anchor" href="#kesalahan-pembayaran" aria-label="Permalink to &quot;Kesalahan Pembayaran&quot;">​</a></h2><h3 id="_13-nominal-transfer-tidak-sesuai" tabindex="-1">13. Nominal Transfer Tidak Sesuai <a class="header-anchor" href="#_13-nominal-transfer-tidak-sesuai" aria-label="Permalink to &quot;13. Nominal Transfer Tidak Sesuai&quot;">​</a></h3><p><strong>Masalah:</strong> Mentransfer dengan nominal kurang atau lebih.</p><p><strong>Solusi:</strong> Transfer sesuai nominal tagihan <strong>persis</strong> (termasuk koma jika ada).</p><h3 id="_14-bukti-transfer-tidak-jelas" tabindex="-1">14. Bukti Transfer Tidak Jelas <a class="header-anchor" href="#_14-bukti-transfer-tidak-jelas" aria-label="Permalink to &quot;14. Bukti Transfer Tidak Jelas&quot;">​</a></h3><p><strong>Masalah:</strong> Foto bukti transfer buram, terpotong, atau tidak terbaca.</p><p><strong>Solusi:</strong></p><ul><li>Pastikan nominal, tanggal, dan nama terlihat jelas</li><li>Gunakan screenshot dari aplikasi banking</li><li>Jangan crop bagian informasi penting</li></ul><h3 id="_15-transfer-ke-rekening-salah" tabindex="-1">15. Transfer ke Rekening Salah <a class="header-anchor" href="#_15-transfer-ke-rekening-salah" aria-label="Permalink to &quot;15. Transfer ke Rekening Salah&quot;">​</a></h3><p><strong>Masalah:</strong> Transfer ke rekening yang tidak terdaftar.</p><p><strong>Solusi:</strong> Periksa 3 kali nomor rekening sebelum transfer.</p><h2 id="kesalahan-teknis" tabindex="-1">Kesalahan Teknis <a class="header-anchor" href="#kesalahan-teknis" aria-label="Permalink to &quot;Kesalahan Teknis&quot;">​</a></h2><h3 id="_16-koneksi-internet-putus-saat-upload" tabindex="-1">16. Koneksi Internet Putus Saat Upload <a class="header-anchor" href="#_16-koneksi-internet-putus-saat-upload" aria-label="Permalink to &quot;16. Koneksi Internet Putus Saat Upload&quot;">​</a></h3><p><strong>Solusi:</strong></p><ul><li>Gunakan koneksi kabel (LAN) jika memungkinkan</li><li>Upload file satu per satu di setiap tab</li><li>Hindari upload di jam sibuk</li></ul><h3 id="_17-browser-tidak-update" tabindex="-1">17. Browser Tidak Update <a class="header-anchor" href="#_17-browser-tidak-update" aria-label="Permalink to &quot;17. Browser Tidak Update&quot;">​</a></h3><p><strong>Solusi:</strong> Gunakan browser versi terbaru (Chrome/Firefox/Edge).</p><h3 id="_18-cache-bermasalah" tabindex="-1">18. Cache Bermasalah <a class="header-anchor" href="#_18-cache-bermasalah" aria-label="Permalink to &quot;18. Cache Bermasalah&quot;">​</a></h3><p><strong>Solusi:</strong> Clear cache browser atau gunakan mode incognito.</p><h2 id="daftar-periksa-sebelum-submit" tabindex="-1">Daftar Periksa Sebelum Submit <a class="header-anchor" href="#daftar-periksa-sebelum-submit" aria-label="Permalink to &quot;Daftar Periksa Sebelum Submit&quot;">​</a></h2><p>Sebelum mengirim pendaftaran, periksa hal berikut:</p><ul><li>[ ] Nama sesuai KTP</li><li>[ ] Tanggal lahir benar</li><li>[ ] Nomor HP aktif</li><li>[ ] Email benar</li><li>[ ] Semua field terisi di setiap tab</li><li>[ ] Semua pertanyaan deskripsi diri dijawab lengkap</li><li>[ ] Dokumen format JPG</li><li>[ ] Ukuran file di bawah 1 MB</li><li>[ ] Resolusi maksimal 2500 x 1600 px</li><li>[ ] Dokumen terbaca jelas</li><li>[ ] Ijazah sudah dilegalisir</li><li>[ ] Transfer nominal tepat</li><li>[ ] Bukti transfer jelas</li></ul>',64))])}const T=t(m,[["render",p]]);export{S as __pageData,T as default};
